                    appList = AppCache.getCachedApps() ?: listOf()
                }
                isLoading = false
            }

            AlertDialog(
                onDismissRequest = { showList = false },
                properties = androidx.compose.ui.window.DialogProperties(usePlatformDefaultWidth = false),
                modifier = Modifier.fillMaxWidth(0.95f).clip(RoundedCornerShape(24.dp)),
                title = { Text("SAFE APP REGISTRY", fontSize = 18.sp, fontWeight = FontWeight.ExtraBold, color = Color.White) },
                containerColor = Color(0xFF0A0A0A),
                text = {
                    Column(modifier = Modifier.heightIn(max = 550.dp)) {
                        OutlinedTextField(
                            value = filter,
                            onValueChange = { filter = it },
