                            Box(modifier = Modifier.fillMaxWidth().height(300.dp), contentAlignment = Alignment.Center) {
                                CircularProgressIndicator(color = Color(0xFF818CF8))
                            }
                        } else {
                            val filtered = appList.filter { it.name.contains(filter, ignoreCase = true) || it.pkg.contains(filter, ignoreCase = true) }
                            androidx.compose.foundation.lazy.LazyColumn(modifier = Modifier.weight(1f), verticalArrangement = Arrangement.spacedBy(8.dp)) {
                                items(filtered.size) { index ->
                                    val app = filtered[index]
                                    Surface(
                                        onClick = {
                                            LockManager.setSafeSession(ctx, app.pkg)
                                            val intent = Intent(Settings.ACTION_APPLICATION_DETAILS_SETTINGS)
                                            intent.data = Uri.parse("package:${app.pkg}")
                                            intent.flags = Intent.FLAG_ACTIVITY_NEW_TASK
                                            ctx.startActivity(intent)
                                            showList = false
                                        },
                                        shape = RoundedCornerShape(12.dp),
                                        color = Color(0xFF121212),
                                        border = BorderStroke(1.dp, Color(0xFF1E1E1E))
                                    ) {
                                        Row(modifier = Modifier.fillMaxWidth().padding(12.dp), verticalAlignment = Alignment.CenterVertically) {
                                            Box(modifier = Modifier.size(40.dp).clip(RoundedCornerShape(8.dp)).background(Color(0xFF1A1A1A)), contentAlignment = Alignment.Center) {
                                                Text((app.name.take(1)).uppercase(), color = Color(0xFF818CF8), fontWeight = FontWeight.Bold)
                                            }
                                            Spacer(modifier = Modifier.width(16.dp))
                                            Column(modifier = Modifier.weight(1f)) {
                                                Text(app.name, color = Color.White, fontSize = 14.sp, fontWeight = FontWeight.Bold)
                                                Text(app.pkg, color = Color.Gray, fontSize = 10.sp)
                                            }
                                            Icon(Icons.Default.Shield, null, tint = Color.DarkGray, modifier = Modifier.size(16.dp))
                                        }
                                    }
                                }
                            }
                        }
                    }
                },
                confirmButton = { TextButton(onClick = { showList = false }) { Text("CLOSE REGISTRY", color = Color(0xFF818CF8)) } }
            )
        }
    }

    @Composable fun SetupCard() { /* Implemented in previous turns, omitted for brevity but required */ }
    @Composable fun FocusCard() { /* Implemented in previous turns */ }
