             removeTouchBlocker()
         }
    }

    if (event.repeatCount == 0) {
        val actStr = if (action == KeyEvent.ACTION_DOWN) "DOWN" else "UP"
        DebugLogger.log("KEY", "$actStr Code:$keyCode Long:$isLongPress")
    }

    if (action == KeyEvent.ACTION_DOWN) {
