package com.guardian.net

import android.app.admin.DevicePolicyManager
import android.content.ComponentName
import android.content.Context
import android.content.Intent
import android.net.Uri
import android.os.Bundle
import android.provider.Settings
import androidx.activity.ComponentActivity
import androidx.activity.compose.setContent
import androidx.compose.foundation.BorderStroke
import androidx.compose.foundation.background
import androidx.compose.foundation.clickable
import androidx.compose.foundation.layout.*
import androidx.compose.foundation.rememberScrollState
import androidx.compose.foundation.shape.RectangleShape
import androidx.compose.foundation.text.selection.SelectionContainer
import androidx.compose.foundation.verticalScroll
import androidx.compose.material.icons.Icons
import androidx.compose.material.icons.filled.*
import androidx.compose.material3.*
import androidx.compose.runtime.*
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.graphics.Color
import androidx.compose.ui.platform.LocalContext
import androidx.compose.ui.text.font.FontWeight
import androidx.compose.ui.text.input.PasswordVisualTransformation
import androidx.compose.ui.text.style.TextAlign
import androidx.compose.ui.unit.dp
import androidx.compose.ui.unit.sp
import kotlinx.coroutines.MainScope
import kotlinx.coroutines.delay
import kotlinx.coroutines.launch

class MainActivity : ComponentActivity() {
    override fun onCreate(savedInstanceState: Bundle?) {
        Thread.setDefaultUncaughtExceptionHandler { _, throwable ->
            DebugLogger.logCrash(throwable)
            android.os.Process.killProcess(android.os.Process.myPid())
        }
        super.onCreate(savedInstanceState)

        MainScope().launch { AppCache.loadApps(applicationContext) }

        setContent {
            val prefs = getSharedPreferences("ui_prefs", Context.MODE_PRIVATE)
            var isDark by remember { mutableStateOf(prefs.getBoolean("dark_mode", true)) }

            MaterialTheme(
                colorScheme = if (isDark) darkColorScheme(background = Color.Black, surface = Color(0xFF111111), onBackground = Color.White) 
                              else lightColorScheme(background = Color.White, surface = Color(0xFFF9F9F9), onBackground = Color.Black)
            ) {
                DashboardMain(isDark) { 
                    isDark = !isDark
                    prefs.edit().putBoolean("dark_mode", isDark).apply()
                }
            }
        }
    }

    @Composable
    fun DashboardMain(isDark: Boolean, onThemeToggle: () -> Unit) {
        val ctx = LocalContext.current
        var setupDone by remember { mutableStateOf(LockManager.isSetupComplete(ctx)) }
        val textColor = if (isDark) Color.White else Color.Black
        val subTextColor = if (isDark) Color.Gray else Color(0xFF666666)
        val borderColor = if (isDark) Color(0xFF222222) else Color(0xFFE5E5E5)

        if (!setupDone) {
            OnboardingGate(isDark) { setupDone = true }
        } else {
            LaunchedEffect(Unit) {
                val intent = Intent(ctx, WatcherService::class.java)
                if (android.os.Build.VERSION.SDK_INT >= android.os.Build.VERSION_CODES.O) ctx.startForegroundService(intent) else ctx.startService(intent)
            }

            var missingPerms by remember { mutableStateOf(listOf<PermissionItem>()) }
            LaunchedEffect(Unit) { while(true) { missingPerms = getMissingPermissions(ctx); delay(2000) } }

            Column(modifier = Modifier.fillMaxSize().background(MaterialTheme.colorScheme.background).padding(24.dp).verticalScroll(rememberScrollState())) {
                // HEADER
                Text("GUARDIAN", fontSize = 48.sp, fontWeight = FontWeight.Black, color = textColor, letterSpacing = (-2).sp)
                Row(modifier = Modifier.fillMaxWidth().padding(bottom = 32.dp), horizontalArrangement = Arrangement.SpaceBetween) {
                    Text("SYSTEM VERSION 4.1", fontSize = 10.sp, fontWeight = FontWeight.Bold, color = subTextColor)
                    Text(if (missingPerms.isEmpty()) "COMPLIANT" else "VIOLATION", fontSize = 10.sp, fontWeight = FontWeight.Bold, color = if (missingPerms.isEmpty()) Color(0xFF10B981) else Color(0xFFEF4444))
                }

                if (missingPerms.isNotEmpty()) {
                    ComplianceAlertCard(missingPerms)
                    Spacer(modifier = Modifier.height(24.dp))
                }

                // DASHBOARD GRID
                BrutalistCard("CHAIN TO THE DESK", "00:00:00", "You aren't busy. Start the clock or I will.", isDark) { /* Focus Logic */ }
                Spacer(modifier = Modifier.height(16.dp))
                BrutalistCard("SOLITARY CONFINEMENT", "WHITELIST: INACTIVE", "Only essential apps. No distractions. No mercy.", isDark) { /* Zen Logic */ }
                Spacer(modifier = Modifier.height(16.dp))
                BrutalistCard("THE BLACKLIST", "14 APPS BANNED", "View the digital graveyard of your bad habits.", isDark, isSecondary = true) { /* Vault Logic */ }
                Spacer(modifier = Modifier.height(16.dp))
                BrutalistCard("LAME EXCUSES", "${LockManager.getRemainingNightPasses(ctx)} PASSES LEFT", "Asking for permission to stay up late like a child?", isDark, isSecondary = true) { /* Pass Logic */ }
                Spacer(modifier = Modifier.height(16.dp))
                BrutalistCard("SYSTEM MAINTENANCE", "DNS REPAIR", "Request a 5-minute window to fix your DNS mess.", isDark, isSecondary = true) { /* DNS Logic */ }
                Spacer(modifier = Modifier.height(16.dp))
                BrutalistCard("THE COWARD'S EXIT", "EMERGENCY ONLY", "Initiate protocol. I'll remember this weakness.", isDark, isCoward = true) { /* Nuke Logic */ }

                Spacer(modifier = Modifier.height(48.dp))

                // FOOTER
                Column(horizontalAlignment = Alignment.CenterHorizontally, modifier = Modifier.fillMaxWidth()) {
                    Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceEvenly) {
                        Text("SYSTEM AUTOPSY", fontSize = 10.sp, fontWeight = FontWeight.Black, color = subTextColor, modifier = Modifier.clickable { /* Stats */ })
                        Text("INCIDENT LOGS", fontSize = 10.sp, fontWeight = FontWeight.Black, color = subTextColor, modifier = Modifier.clickable { /* Logs */ })
                    }
                    Spacer(modifier = Modifier.height(24.dp))
                    Button(
                        onClick = onThemeToggle,
                        colors = ButtonDefaults.buttonColors(containerColor = Color.Transparent, contentColor = textColor),
                        border = BorderStroke(1.dp, borderColor),
                        shape = RectangleShape,
                        modifier = Modifier.fillMaxWidth(0.6f)
                    ) {
                        Text("CHANGE PERSPECTIVE", fontSize = 10.sp, fontWeight = FontWeight.Black)
                    }
                }
            }
        }
    }

    @Composable
    fun BrutalistCard(title: String, value: String, desc: String, isDark: Boolean, isSecondary: Boolean = false, isCoward: Boolean = false, onClick: () -> Unit) {
        val textColor = if (isDark) Color.White else Color.Black
        val subTextColor = if (isDark) Color.Gray else Color(0xFF666666)
        val cardBg = if (isDark) Color(0xFF111111) else Color(0xFFF9F9F9)
        val borderColor = if (isDark) Color(0xFF222222) else Color(0xFFE5E5E5)

        Card(shape = RectangleShape, colors = CardDefaults.cardColors(containerColor = cardBg), border = BorderStroke(1.dp, borderColor), modifier = Modifier.fillMaxWidth()) {
            Column(modifier = Modifier.padding(24.dp)) {
                Text(title, fontSize = 10.sp, fontWeight = FontWeight.Bold, letterSpacing = 2.sp, color = subTextColor)
                Spacer(modifier = Modifier.height(8.dp))
                Text(value, fontSize = 24.sp, fontWeight = FontWeight.Bold, color = textColor)
                Text(desc, fontSize = 12.sp, color = subTextColor, modifier = Modifier.padding(top = 4.dp))

                Button(
                    onClick = onClick,
                    modifier = Modifier.fillMaxWidth().padding(top = 20.dp),
                    shape = RectangleShape,
                    colors = ButtonDefaults.buttonColors(
                        containerColor = if (isCoward) Color.Transparent else if (isSecondary) Color.Transparent else textColor,
                        contentColor = if (isCoward) Color(0xFFEF4444) else if (isSecondary) textColor else if (isDark) Color.Black else Color.White
                    ),
                    border = if (isCoward) BorderStroke(1.dp, Color(0xFFEF4444)) else if (isSecondary) BorderStroke(1.dp, textColor) else null
                ) {
                    Text("EXECUTE", fontWeight = FontWeight.Black, fontSize = 12.sp)
                }
            }
        }
    }

    @Composable
    fun ComplianceAlertCard(missing: List<PermissionItem>) {
        Card(shape = RectangleShape, colors = CardDefaults.cardColors(containerColor = Color(0xFF450A0A)), border = BorderStroke(2.dp, Color(0xFFEF4444)), modifier = Modifier.fillMaxWidth()) {
            Column(modifier = Modifier.padding(16.dp)) {
                Text("COMPLIANCE VIOLATION", color = Color(0xFFEF4444), fontWeight = FontWeight.Black, fontSize = 14.sp)
                Text("Fix the following immediately or face restrictions.", color = Color.White.copy(alpha = 0.7f), fontSize = 11.sp)
                Spacer(modifier = Modifier.height(12.dp))
                missing.forEach { item ->
                    Row(modifier = Modifier.fillMaxWidth().clickable { item.action(applicationContext) }.padding(vertical = 8.dp), horizontalArrangement = Arrangement.SpaceBetween) {
                        Text(item.label, color = Color.White, fontWeight = FontWeight.Bold, fontSize = 13.sp)
                        Icon(Icons.Filled.ChevronRight, null, tint = Color.Gray)
                    }
                }
            }
        }
    }

    @Composable
    fun OnboardingGate(isDark: Boolean, onSetupComplete: () -> Unit) {
        val ctx = LocalContext.current
        var missing by remember { mutableStateOf(listOf<String>()) }
        LaunchedEffect(Unit) { while (true) { 
            val list = getMissingPermissions(ctx)
            missing = list.map { it.label }
            if (list.isEmpty()) { LockManager.setSetupComplete(ctx); onSetupComplete(); break }
            delay(1000) 
        } }

        Box(modifier = Modifier.fillMaxSize().background(if(isDark) Color.Black else Color.White).padding(32.dp), contentAlignment = Alignment.Center) {
            Column(horizontalAlignment = Alignment.Start) {
                Text("PROTOCOL", fontSize = 48.sp, fontWeight = FontWeight.Black, color = if(isDark) Color.White else Color.Black)
                Text("INITIALIZATION", fontSize = 48.sp, fontWeight = FontWeight.Black, color = if(isDark) Color.White else Color.Black)
                Spacer(modifier = Modifier.height(16.dp))
                Text("The system requires total control. Comply or delete the application.", color = Color.Gray, fontSize = 14.sp)
                Spacer(modifier = Modifier.height(32.dp))
                missing.forEach { Text("• $it", color = Color(0xFFEF4444), fontWeight = FontWeight.Bold) }
                Spacer(modifier = Modifier.height(32.dp))
                Button(onClick = { getMissingPermissions(ctx).firstOrNull()?.action?.invoke(ctx) }, shape = RectangleShape, colors = ButtonDefaults.buttonColors(containerColor = if(isDark) Color.White else Color.Black)) {
                    Text("AUTHORIZE", color = if(isDark) Color.Black else Color.White, fontWeight = FontWeight.Black)
                }
            }
        }
    }

    data class PermissionItem(val label: String, val action: (Context) -> Unit)
    private fun getMissingPermissions(ctx: Context): List<PermissionItem> {
        val list = mutableListOf<PermissionItem>()
        if (!Settings.canDrawOverlays(ctx)) list.add(PermissionItem("OVERLAY_PERMISSION") { LockManager.startPermissionFixSession(it); it.startActivity(Intent(Settings.ACTION_MANAGE_OVERLAY_PERMISSION, Uri.parse("package:$packageName"))) })
        if (!(ctx.getSystemService(Context.POWER_SERVICE) as android.os.PowerManager).isIgnoringBatteryOptimizations(ctx.packageName)) list.add(PermissionItem("BATTERY_OPTIMIZATION") { it.startActivity(Intent(Settings.ACTION_REQUEST_IGNORE_BATTERY_OPTIMIZATIONS, Uri.parse("package:$packageName"))) })
        val expected = "$packageName/${GuardService::class.java.canonicalName}"
        if (!(Settings.Secure.getString(ctx.contentResolver, Settings.Secure.ENABLED_ACCESSIBILITY_SERVICES) ?: "").contains(expected)) list.add(PermissionItem("ACCESSIBILITY_SERVICE") { it.startActivity(Intent(Settings.ACTION_ACCESSIBILITY_SETTINGS)) })
        if (!(ctx.getSystemService(Context.DEVICE_POLICY_SERVICE) as DevicePolicyManager).isAdminActive(ComponentName(ctx, AdminReceiver::class.java))) list.add(PermissionItem("DEVICE_ADMIN") { val i = Intent(DevicePolicyManager.ACTION_ADD_DEVICE_ADMIN); i.putExtra(DevicePolicyManager.EXTRA_DEVICE_ADMIN, ComponentName(it, AdminReceiver::class.java)); it.startActivity(i) })
        if (checkSelfPermission(android.Manifest.permission.READ_CALL_LOG) != android.content.pm.PackageManager.PERMISSION_GRANTED) list.add(PermissionItem("CALL_LOG_ACCESS") { requestPermissions(arrayOf(android.Manifest.permission.READ_CALL_LOG, android.Manifest.permission.READ_PHONE_STATE), 101) })
        return list
    }
}

package com.guardian.net

import android.content.ClipData
import android.content.ClipboardManager
import android.content.Context
import android.content.Intent
import android.os.Bundle
import android.widget.Toast
import androidx.activity.ComponentActivity
import androidx.activity.compose.setContent
import androidx.compose.foundation.BorderStroke
import androidx.compose.foundation.background
import androidx.compose.foundation.layout.*
import androidx.compose.foundation.shape.RectangleShape
import androidx.compose.material.icons.Icons
import androidx.compose.material.icons.filled.*
import androidx.compose.material3.*
import androidx.compose.runtime.*
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.graphics.Color
import androidx.compose.ui.graphics.vector.ImageVector
import androidx.compose.ui.text.font.FontWeight
import androidx.compose.ui.text.input.PasswordVisualTransformation
import androidx.compose.ui.text.style.TextAlign
import androidx.compose.ui.unit.dp
import androidx.compose.ui.unit.sp
import kotlinx.coroutines.delay

class LockdownActivity : ComponentActivity() {
    private var blockTypeState = mutableStateOf("SYSTEM")

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        blockTypeState.value = intent.getStringExtra("BLOCK_TYPE") ?: "SYSTEM"
        window.setFlags(android.view.WindowManager.LayoutParams.FLAG_LAYOUT_NO_LIMITS, android.view.WindowManager.LayoutParams.FLAG_LAYOUT_NO_LIMITS)

        setContent {
            val uiConfig = getUiConfig(blockTypeState.value)
            var showPassDialog by remember { mutableStateOf(false) }

            Box(modifier = Modifier.fillMaxSize().background(Color.Black).padding(32.dp), contentAlignment = Alignment.Center) {
                Column(horizontalAlignment = Alignment.Start, modifier = Modifier.fillMaxWidth()) {
                    Text(uiConfig.title, color = Color.White, fontSize = 48.sp, fontWeight = FontWeight.Black, lineHeight = 50.sp)
                    Spacer(modifier = Modifier.height(16.dp))
                    Text(blockTypeState.value.replace("_", " "), color = Color(0xFFEF4444), fontSize = 12.sp, fontWeight = FontWeight.Bold, letterSpacing = 2.sp)
                    Spacer(modifier = Modifier.height(24.dp))
                    Text(uiConfig.description, color = Color.Gray, fontSize = 16.sp, fontWeight = FontWeight.Medium)

                    Spacer(modifier = Modifier.height(48.dp))

                    if (blockTypeState.value == "SYSTEM") {
                        DnsManager.ALLOWED_HOSTNAMES.forEach { host ->
                            Button(
                                onClick = { 
                                    val clipboard = getSystemService(Context.CLIPBOARD_SERVICE) as ClipboardManager
                                    clipboard.setPrimaryClip(ClipData.newPlainText("DNS", host))
                                    Toast.makeText(applicationContext, "COPIED", Toast.LENGTH_SHORT).show()
                                },
                                modifier = Modifier.fillMaxWidth().padding(vertical = 4.dp),
                                shape = RectangleShape,
                                colors = ButtonDefaults.buttonColors(containerColor = Color.Transparent, contentColor = Color.White),
                                border = BorderStroke(1.dp, Color(0xFF222222))
                            ) {
                                Text(host, fontSize = 12.sp, fontWeight = FontWeight.Bold)
                            }
                        }
                        Spacer(modifier = Modifier.height(24.dp))
                        Button(
                            onClick = { 
                                LockManager.startPermissionFixSession(applicationContext)
                                try { startActivity(Intent("android.settings.PVT_DNS_SETTINGS").apply { flags = Intent.FLAG_ACTIVITY_NEW_TASK }) } 
                                catch (e: Exception) { startActivity(Intent(android.provider.Settings.ACTION_SETTINGS).apply { flags = Intent.FLAG_ACTIVITY_NEW_TASK }) }
                            },
                            modifier = Modifier.fillMaxWidth().height(60.dp),
                            shape = RectangleShape,
                            colors = ButtonDefaults.buttonColors(containerColor = Color.White, contentColor = Color.Black)
                        ) {
                            Text("FIX CONNECTION", fontWeight = FontWeight.Black)
                        }
                    } else {
                        Button(
                            onClick = { 
                                val home = Intent(Intent.ACTION_MAIN).apply { addCategory(Intent.CATEGORY_HOME); flags = Intent.FLAG_ACTIVITY_NEW_TASK }
                                startActivity(home) 
                            },
                            modifier = Modifier.fillMaxWidth().height(60.dp),
                            shape = RectangleShape,
                            colors = ButtonDefaults.buttonColors(containerColor = Color(0xFFEF4444), contentColor = Color.Black)
                        ) {
                            Text("UNDERSTOOD", fontWeight = FontWeight.Black)
                        }
                    }
                }

                if (showPassDialog) {
                    MaintenanceDialog(onDismiss = { showPassDialog = false }) { 
                        LockManager.unlock(applicationContext)
                        finishAffinity() 
                    }
                }
            }

            LaunchedEffect(blockTypeState.value) {
                while(true) {
                    val ctx = applicationContext
                    val shouldClose = when (blockTypeState.value) {
                        "SYSTEM" -> DnsManager.isSecure(ctx) || LockManager.isUnlocked(ctx)
                        "NIGHT_LOCK" -> !LockManager.isNightLockActive(ctx)
                        "BREAK_TIME" -> LockManager.getBreakRemaining(ctx) <= 0
                        "USER_LOCKOUT" -> !LockManager.isUserLockedOut(ctx)
                        "PENALTY" -> LockManager.getPenaltyRemaining(ctx) <= 0 && !LockManager.isSystemCompromised(ctx)
                        "BROWSER_VIOLATION" -> !LockManager.isBrowserBanned(ctx)
                        "TELEGRAM_SUSPENDED" -> !LockManager.isTelegramBanned(ctx)
                        "DEEP_FOCUS" -> LockManager.getDeepFocusRemaining(ctx) <= 0
                        else -> false
                    }
                    if (shouldClose) { finishAffinity(); break }
                    delay(2000)
                }
            }
        }
    }

    @Composable
    private fun MaintenanceDialog(onDismiss: () -> Unit, onCorrect: () -> Unit) {
        var text by remember { mutableStateOf("") }
        AlertDialog(
            onDismissRequest = onDismiss,
            shape = RectangleShape,
            title = { Text("DNS REPAIR ACCESS", fontWeight = FontWeight.Black) },
            text = { OutlinedTextField(value = text, onValueChange = { text = it }, visualTransformation = PasswordVisualTransformation(), shape = RectangleShape) },
            confirmButton = { Button(onClick = { if (text == "1234") onCorrect() }, shape = RectangleShape) { Text("UNLOCK") } }
        )
    }

    private fun getUiConfig(type: String): UiConfig {
        return when (type) {
            "BROWSER_VIOLATION" -> UiConfig(Icons.Filled.Block, "GET\nREKT", "No browsing permitted. Stick to your tasks.")
            "TELEGRAM_SUSPENDED" -> UiConfig(Icons.Filled.Lock, "TOUCH\nGRASS", "Telegram access revoked. Your time is mine now.")
            "NIGHT_LOCK" -> UiConfig(Icons.Filled.NightsStay, "GO TO\nSLEEP", "It is past your bedtime. Compliance is mandatory.")
            "BREAK_TIME" -> UiConfig(Icons.Filled.Timer, "CHILL\nOUT", "The system mandates a rest period. Sit still.")
            "USER_LOCKOUT" -> UiConfig(Icons.Filled.Timer, "LOCKED\nIN", "Focus session active. Do not deviate.")
            "PENALTY" -> UiConfig(Icons.Filled.Warning, "PENALTY\nBOX", "Tamper detection triggered. Servicing penalty time.")
            "ROGUE_VIOLATION" -> UiConfig(Icons.Filled.Block, "NICE\nTRY", "That application is permanently banned.")
            "SECURITY_TRIPWIRE" -> UiConfig(Icons.Filled.Shield, "I SEE\nYOU", "Stay out of restricted system settings.")
            "DEEP_FOCUS" -> UiConfig(Icons.Filled.CenterFocusStrong, "ZEN\nMODE", "Whitelist enforcement active. Stay focused.")
            else -> UiConfig(Icons.Filled.Shield, "YOU\nTHOUGHT?", "DNS hijacking detected. Secure the connection.")
        }
    }

    data class UiConfig(val icon: ImageVector, val title: String, val description: String)
    override fun onBackPressed() { }
}

