    @Composable
    fun OnboardingGate(isDark: Boolean, onSetupComplete: () -> Unit) {
        val ctx = LocalContext.current
        var missing by remember { mutableStateOf(listOf<String>()) }
        LaunchedEffect(Unit) { while (true) { 
            val list = getMissingPermissions(ctx)
            missing = list.map { it.label }
            if (list.isEmpty()) { LockManager.setSetupComplete(ctx); onSetupComplete(); break }
            delay(1000) 
        } }

        Box(modifier = Modifier.fillMaxSize().background(if(isDark) Color.Black else Color.White).padding(32.dp), contentAlignment = Alignment.Center) {
            Column(horizontalAlignment = Alignment.Start) {
                Text("PROTOCOL", fontSize = 48.sp, fontWeight = FontWeight.Black, color = if(isDark) Color.White else Color.Black)
                Text("INITIALIZATION", fontSize = 48.sp, fontWeight = FontWeight.Black, color = if(isDark) Color.White else Color.Black)
                Spacer(modifier = Modifier.height(16.dp))
                Text("The system requires total control. Comply or delete the application.", color = Color.Gray, fontSize = 14.sp)
                Spacer(modifier = Modifier.height(32.dp))
                missing.forEach { Text("• $it", color = Color(0xFFEF4444), fontWeight = FontWeight.Bold) }
                Spacer(modifier = Modifier.height(32.dp))
                Button(onClick = { getMissingPermissions(ctx).firstOrNull()?.action?.invoke(ctx) }, shape = RectangleShape, colors = ButtonDefaults.buttonColors(containerColor = if(isDark) Color.White else Color.Black)) {
                    Text("AUTHORIZE", color = if(isDark) Color.Black else Color.White, fontWeight = FontWeight.Black)
                }
            }
        }
    }

    data class PermissionItem(val label: String, val action: (Context) -> Unit)
    private fun getMissingPermissions(ctx: Context): List<PermissionItem> {
        val list = mutableListOf<PermissionItem>()
        if (!Settings.canDrawOverlays(ctx)) list.add(PermissionItem("OVERLAY_PERMISSION") { LockManager.startPermissionFixSession(it); it.startActivity(Intent(Settings.ACTION_MANAGE_OVERLAY_PERMISSION, Uri.parse("package:$packageName"))) })
        if (!(ctx.getSystemService(Context.POWER_SERVICE) as android.os.PowerManager).isIgnoringBatteryOptimizations(ctx.packageName)) list.add(PermissionItem("BATTERY_OPTIMIZATION") { it.startActivity(Intent(Settings.ACTION_REQUEST_IGNORE_BATTERY_OPTIMIZATIONS, Uri.parse("package:$packageName"))) })
        val expected = "$packageName/${GuardService::class.java.canonicalName}"
        if (!(Settings.Secure.getString(ctx.contentResolver, Settings.Secure.ENABLED_ACCESSIBILITY_SERVICES) ?: "").contains(expected)) list.add(PermissionItem("ACCESSIBILITY_SERVICE") { it.startActivity(Intent(Settings.ACTION_ACCESSIBILITY_SETTINGS)) })
        if (!(ctx.getSystemService(Context.DEVICE_POLICY_SERVICE) as DevicePolicyManager).isAdminActive(ComponentName(ctx, AdminReceiver::class.java))) list.add(PermissionItem("DEVICE_ADMIN") { val i = Intent(DevicePolicyManager.ACTION_ADD_DEVICE_ADMIN); i.putExtra(DevicePolicyManager.EXTRA_DEVICE_ADMIN, ComponentName(it, AdminReceiver::class.java)); it.startActivity(i) })
        if (checkSelfPermission(android.Manifest.permission.READ_CALL_LOG) != android.content.pm.PackageManager.PERMISSION_GRANTED) list.add(PermissionItem("CALL_LOG_ACCESS") { requestPermissions(arrayOf(android.Manifest.permission.READ_CALL_LOG, android.Manifest.permission.READ_PHONE_STATE), 101) })
        return list
    }
}

