class LockdownActivity : ComponentActivity() {
    private var blockTypeState = mutableStateOf("SYSTEM")

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        blockTypeState.value = intent.getStringExtra("BLOCK_TYPE") ?: "SYSTEM"
        window.setFlags(android.view.WindowManager.LayoutParams.FLAG_LAYOUT_NO_LIMITS, android.view.WindowManager.LayoutParams.FLAG_LAYOUT_NO_LIMITS)

        setContent {
            val uiConfig = getUiConfig(blockTypeState.value)
            var showPassDialog by remember { mutableStateOf(false) }

            Box(modifier = Modifier.fillMaxSize().background(Color.Black).padding(32.dp), contentAlignment = Alignment.Center) {
                Column(horizontalAlignment = Alignment.Start, modifier = Modifier.fillMaxWidth()) {
                    Text(uiConfig.title, color = Color.White, fontSize = 48.sp, fontWeight = FontWeight.Black, lineHeight = 50.sp)
                    Spacer(modifier = Modifier.height(16.dp))
                    Text(blockTypeState.value.replace("_", " "), color = Color(0xFFEF4444), fontSize = 12.sp, fontWeight = FontWeight.Bold, letterSpacing = 2.sp)
                    Spacer(modifier = Modifier.height(24.dp))
                    Text(uiConfig.description, color = Color.Gray, fontSize = 16.sp, fontWeight = FontWeight.Medium)

                    Spacer(modifier = Modifier.height(48.dp))

                    if (blockTypeState.value == "SYSTEM") {
                        DnsManager.ALLOWED_HOSTNAMES.forEach { host ->
                            Button(
                                onClick = { 
                                    val clipboard = getSystemService(Context.CLIPBOARD_SERVICE) as ClipboardManager
                                    clipboard.setPrimaryClip(ClipData.newPlainText("DNS", host))
                                    Toast.makeText(applicationContext, "COPIED", Toast.LENGTH_SHORT).show()
                                },
                                modifier = Modifier.fillMaxWidth().padding(vertical = 4.dp),
                                shape = RectangleShape,
                                colors = ButtonDefaults.buttonColors(containerColor = Color.Transparent, contentColor = Color.White),
                                border = BorderStroke(1.dp, Color(0xFF222222))
                            ) {
                                Text(host, fontSize = 12.sp, fontWeight = FontWeight.Bold)
                            }
                        }
                        Spacer(modifier = Modifier.height(24.dp))
                        Button(
                            onClick = { 
                                LockManager.startPermissionFixSession(applicationContext)
                                try { startActivity(Intent("android.settings.PVT_DNS_SETTINGS").apply { flags = Intent.FLAG_ACTIVITY_NEW_TASK }) } 
                                catch (e: Exception) { startActivity(Intent(android.provider.Settings.ACTION_SETTINGS).apply { flags = Intent.FLAG_ACTIVITY_NEW_TASK }) }
                            },
                            modifier = Modifier.fillMaxWidth().height(60.dp),
                            shape = RectangleShape,
                            colors = ButtonDefaults.buttonColors(containerColor = Color.White, contentColor = Color.Black)
                        ) {
                            Text("FIX CONNECTION", fontWeight = FontWeight.Black)
                        }
                    } else {
                        Button(
                            onClick = { 
                                val home = Intent(Intent.ACTION_MAIN).apply { addCategory(Intent.CATEGORY_HOME); flags = Intent.FLAG_ACTIVITY_NEW_TASK }
                                startActivity(home) 
                            },
                            modifier = Modifier.fillMaxWidth().height(60.dp),
                            shape = RectangleShape,
                            colors = ButtonDefaults.buttonColors(containerColor = Color(0xFFEF4444), contentColor = Color.Black)
                        ) {
                            Text("UNDERSTOOD", fontWeight = FontWeight.Black)
                        }
                    }
                }

                if (showPassDialog) {
                    MaintenanceDialog(onDismiss = { showPassDialog = false }) { 
                        LockManager.unlock(applicationContext)
                        finishAffinity() 
                    }
                }
            }

            LaunchedEffect(blockTypeState.value) {
                while(true) {
                    val ctx = applicationContext
                    val shouldClose = when (blockTypeState.value) {
                        "SYSTEM" -> DnsManager.isSecure(ctx) || LockManager.isUnlocked(ctx)
                        "NIGHT_LOCK" -> !LockManager.isNightLockActive(ctx)
                        "BREAK_TIME" -> LockManager.getBreakRemaining(ctx) <= 0
                        "USER_LOCKOUT" -> !LockManager.isUserLockedOut(ctx)
                        "PENALTY" -> LockManager.getPenaltyRemaining(ctx) <= 0 && !LockManager.isSystemCompromised(ctx)
                        "BROWSER_VIOLATION" -> !LockManager.isBrowserBanned(ctx)
                        "TELEGRAM_SUSPENDED" -> !LockManager.isTelegramBanned(ctx)
                        "DEEP_FOCUS" -> LockManager.getDeepFocusRemaining(ctx) <= 0
                        else -> false
                    }
                    if (shouldClose) { finishAffinity(); break }
                    delay(2000)
                }
            }
        }
    }

    @Composable
    private fun MaintenanceDialog(onDismiss: () -> Unit, onCorrect: () -> Unit) {
        var text by remember { mutableStateOf("") }
        AlertDialog(
            onDismissRequest = onDismiss,
            shape = RectangleShape,
            title = { Text("DNS REPAIR ACCESS", fontWeight = FontWeight.Black) },
            text = { OutlinedTextField(value = text, onValueChange = { text = it }, visualTransformation = PasswordVisualTransformation(), shape = RectangleShape) },
            confirmButton = { Button(onClick = { if (text == "1234") onCorrect() }, shape = RectangleShape) { Text("UNLOCK") } }
        )
    }

    private fun getUiConfig(type: String): UiConfig {
        return when (type) {
            "BROWSER_VIOLATION" -> UiConfig(Icons.Filled.Block, "GET\nREKT", "No browsing permitted. Stick to your tasks.")
            "TELEGRAM_SUSPENDED" -> UiConfig(Icons.Filled.Lock, "TOUCH\nGRASS", "Telegram access revoked. Your time is mine now.")
            "NIGHT_LOCK" -> UiConfig(Icons.Filled.NightsStay, "GO TO\nSLEEP", "It is past your bedtime. Compliance is mandatory.")
            "BREAK_TIME" -> UiConfig(Icons.Filled.Timer, "CHILL\nOUT", "The system mandates a rest period. Sit still.")
            "USER_LOCKOUT" -> UiConfig(Icons.Filled.Timer, "LOCKED\nIN", "Focus session active. Do not deviate.")
            "PENALTY" -> UiConfig(Icons.Filled.Warning, "PENALTY\nBOX", "Tamper detection triggered. Servicing penalty time.")
            "ROGUE_VIOLATION" -> UiConfig(Icons.Filled.Block, "NICE\nTRY", "That application is permanently banned.")
            "SECURITY_TRIPWIRE" -> UiConfig(Icons.Filled.Shield, "I SEE\nYOU", "Stay out of restricted system settings.")
            "DEEP_FOCUS" -> UiConfig(Icons.Filled.CenterFocusStrong, "ZEN\nMODE", "Whitelist enforcement active. Stay focused.")
            else -> UiConfig(Icons.Filled.Shield, "YOU\nTHOUGHT?", "DNS hijacking detected. Secure the connection.")
        }
    }

    data class UiConfig(val icon: ImageVector, val title: String, val description: String)
    override fun onBackPressed() { }
}

